const body = $json.body || $json;
const id = String(body.id || ('promo-ui-' + Date.now())).trim();
const md = body.md || {};
const promo = body.promo || {};
const design = body.design || {};
const output = body.output || {};
const model = String(body.model || 'gpt-4o-mini').trim();
const imageModel = String(
  body.imageModel ||
  body.image_model ||
  'models/gemini-3.1-flash-image'
).trim();
const n8nWebhookUrl = String(body.n8nWebhookUrl || body.n8n_webhook_url || '').trim();
const promptUrl = String(body.promptUrl || body.prompt_url || '').trim();
const integratedBriefPromptUrl = String(body.integratedBriefPromptUrl || body.integrated_brief_prompt_url || '').trim();
const template = body.template || { id: 'temp4', name: 'Template 4', generationMode: 'ai_agent', inputMode: 'simple' };
const simpleBrief = body.simpleBrief || {};
const sectionInputs = body.sectionInputs || {};

const requiredPromo = ['title', 'template', 'market', 'leadText', 'ctaLabel', 'ctaUrl', 'subline', 'termsText'];
const missingPromo = requiredPromo.filter((key) => !String(promo[key] || '').trim());
if (missingPromo.length) throw new Error('Missing promo fields: ' + missingPromo.join(', '));
if (!md.brand) throw new Error('md.brand is required');
if (!md.designConcept && !md.designPromptContext) throw new Error('md.designConcept or md.designPromptContext is required');

return [{
  json: {
    id,
    model,
    imageModel,
    n8nWebhookUrl,
    promptUrl,
    integratedBriefPromptUrl,
    md,
    promo,
    template,
    simpleBrief,
    sectionInputs,
    design,
    sourceDesign: body.sourceDesign || {},
    styleSource: body.styleSource || '',
    styleSourceLabel: body.styleSourceLabel || '',
    companyPreset: body.companyPreset || null,
    hasOverride: Boolean(body.hasOverride),
    output: {
      format: output.format || 'ui_design_image',
      stage: output.stage || 'design_image_generation',
      viewport: output.viewport || { width: 1440, minWidth: 1180, height: 2200 },
      imageSize: output.imageSize || '1024x1536',
      aspectRatio: output.aspectRatio || output.aspect_ratio || '3:4'
    }
  }
}];

const input = $('Build Source Markdown Preview').item.json;
const loadedPrompt = $json;

const promptTemplate = String(
  loadedPrompt.prompt ||
  loadedPrompt.body?.prompt ||
  loadedPrompt.data?.prompt ||
  ''
).trim();

if (!promptTemplate) {
  throw new Error('External integrated design brief prompt is empty');
}

const designPromptMarkdown = String(input.designPromptMarkdown || '').trim();
const sectionInputLogMarkdown = String(input.sectionInputLogMarkdown || '').trim();
if (!designPromptMarkdown) throw new Error('Design Prompt MD markdown is required');
if (!sectionInputLogMarkdown) throw new Error('Section Input Log MD markdown is required');

const render = (template, data) => template.replace(/{{\s*([a-zA-Z0-9_]+)\s*}}/g, (match, key) => (
  Object.prototype.hasOwnProperty.call(data, key) ? String(data[key]) : match
));

const templateSectionOrder = Array.isArray(input.template?.sectionOrder)
  ? input.template.sectionOrder.join(', ')
  : '';

const values = {
  runKey: input.id,
  promptGroupId: input.promptGroupId || '',
  promoTitle: input.promo?.title || '',
  selectedMd: input.md?.brand || '',
  selectedMdSlug: input.md?.slug || '',
  templateId: input.template?.id || '',
  templateName: input.template?.name || input.template?.id || 'Selected template',
  templateSectionOrder,
  pageContext: '1440px desktop promotional Web UI mockup',
  designPromptMarkdown,
  sectionInputLogMarkdown
};

const integrationPrompt = render(promptTemplate, values);

return [{
  json: {
    ...input,
    designPromptMarkdown,
    sectionInputLogMarkdown,
    integratedBriefPromptMeta: {
      id: loadedPrompt.id || loadedPrompt.body?.id || 'promo-integrated-design-brief-generation',
      version: loadedPrompt.version || loadedPrompt.body?.version || '',
      url: input.integratedBriefPromptUrl || 'https://promo-web-builder.vercel.app/api/prompts/promo-integrated-design-brief-generation'
    },
    integratedBriefRequest: {
      model: input.model,
      messages: [
        { role: 'system', content: 'You are a senior product UI design systems architect. Return valid JSON only. Create a complete, self-contained Integrated Design Brief MD for a browserless promotional Web UI mockup. Treat the selected Design Prompt MD primarily as design tokens and style guardrails, and treat the B-section Section Input Log MD as the primary source for content, structure, emphasis, selected options, and generation intent. Preserve B-section intent when priorities conflict, and apply MD tokens as styling constraints. The downstream Web UI design must be generated from the integrated brief alone.' },
        { role: 'user', content: integrationPrompt }
      ],
      temperature: 0.16,
      response_format: { type: 'json_object' }
    }
  }
}];

const input = $('Build Integrated Design Brief Request').item.json;
const response = $json;
const content = response.choices?.[0]?.message?.content || response.message?.content || response.content || response.text || response.output_text || '';
if (!content) throw new Error('Integrated design brief response is empty');

let generated;
try {
  const fence = String.fromCharCode(96, 96, 96);
  generated = typeof content === 'string'
    ? JSON.parse(content.replace(new RegExp('^' + fence + 'json\\s*', 'i'), '').replace(new RegExp(fence + '$', 'i'), '').trim())
    : content;
} catch (error) {
  throw new Error('Failed to parse integrated design brief JSON: ' + error.message);
}

const markdown = String(generated.integratedDesignBriefMarkdown || '').trim();
const brief = generated.integratedDesignBrief || {};
if (!markdown) throw new Error('integratedDesignBriefMarkdown is required');
if (markdown.length < 6000) throw new Error('Integrated design brief is too short; expected a complete self-contained request document');
if (!brief || typeof brief !== 'object') throw new Error('integratedDesignBrief is required');

const requiredHeadings = [
  '# Integrated Design Brief MD',
  '## Source Priority Rules',
  '## Resolved Conflicts',
  '## Non-Negotiable Rules',
  '## MD Compliance Map',
  '## Design Token Application',
  '## Section Content Mapping',
  '## Token-to-Section Application',
  '## Design Style Basis',
  '## Visual Direction',
  '## Final Image Prompt Inputs',
  '## Negative Prompt',
  '## Visual QA Checklist'
];
const missingHeadings = requiredHeadings.filter((heading) => !markdown.includes(heading));
if (missingHeadings.length) throw new Error('Integrated design brief missing sections: ' + missingHeadings.join(', '));

const requiredTemplateSections = ['### Header', '### Hero Banner', '### Step Bar', '### Content CTA', '### Image Text Row', '### Title and Description', '### Footer'];
const missingTemplateSections = requiredTemplateSections.filter((section) => !markdown.includes(section));
if (missingTemplateSections.length) throw new Error('Integrated design brief missing Template 4 mappings: ' + missingTemplateSections.join(', '));

const bulletCount = (markdown.match(/(^|\n)\s*[-*]\s+/g) || []).length;
if (bulletCount < 25) throw new Error('Integrated design brief is too shallow; expected at least 25 traceability bullets');

const lowerMarkdown = markdown.toLowerCase();
const requiredConflictChecks = [
  { label: 'Source Priority Rules', ok: lowerMarkdown.includes('source priority') || lowerMarkdown.includes('source-priority') },
  { label: 'Resolved Conflicts', ok: lowerMarkdown.includes('resolved conflict') || lowerMarkdown.includes('conflict resolution') || lowerMarkdown.includes('conflicts') }
];
const missingConflictTerms = requiredConflictChecks.filter((check) => !check.ok).map((check) => check.label);
if (missingConflictTerms.length) throw new Error('Integrated design brief missing source-priority/conflict-resolution detail: ' + missingConflictTerms.join(', '));

const forbiddenReferencePhrases = [
  'refer to design prompt md',
  'see design prompt md',
  'refer to section input log',
  'see section input log',
  'refer to the design prompt',
  'refer to the section input'
];
const usedForbiddenReferences = forbiddenReferencePhrases.filter((phrase) => lowerMarkdown.includes(phrase));
if (usedForbiddenReferences.length) throw new Error('Integrated design brief contains forbidden reference phrasing: ' + usedForbiddenReferences.join(', '));

const imagePromptInstruction = [
  'Create the final image-generation prompt using only the integrated design brief below.',
  'Do not rely on the original DESIGN.md, content.md, designBrief JSON, layoutMapping JSON, or any other external context.',
  'The integrated design brief is the single source of truth. If a detail is not in this brief, do not invent it except for minor visual polish.',
  'All visible UI copy in the generated design must be English only. Do not render Korean or any other non-English UI text.',
  '',
  'Return valid JSON only. Do not include markdown fences or explanations outside JSON.',
  '',
  'Return this JSON shape:',
  '{',
  '  "imagePrompt": "single detailed prompt string for a browserless desktop promotional web UI mockup scaled into the bitmap export; it must explicitly include all 7 Template 4 sections, English-only visible copy, web page hierarchy, navigation/header cues, CTA components, section containers, grid rhythm, vertical fit strategy, component style, depth/effects, shape/radius, color/font constraints, and footer/legal content",',
  '  "negativePrompt": "poster, flyer, brochure, print ad, presentation slide, magazine cover, single centered key visual, decorative poster typography, paper margins, cropped bottom, missing footer, missing Title and Description, hero-only screenshot, middle-page screenshot, generic landing page, weak MD compliance, color/font-only reskin, unreadable text, non-English UI copy, Korean text, wrong section order, browser chrome, editor UI, Figma canvas UI",',
  '  "designBrief": { "source": "integratedDesignBriefOnly", "summary": "brief summary of the integrated design brief used" },',
  '  "layoutMapping": { "source": "integratedDesignBriefOnly", "sections": {} },',
  '  "mdComplianceMap": {',
  '    "layoutPhilosophy": "...",',
  '    "visualMood": "...",',
  '    "spacingRhythm": "...",',
  '    "composition": "...",',
  '    "componentStyle": "...",',
  '    "depthAndEffects": "...",',
  '    "shapeAndRadius": "...",',
  '    "promoPageImplications": "...",',
  '    "dosApplied": ["..."],',
  '    "dontsAvoided": ["..."],',
  '    "notColorFontOnlyProof": "..."',
  '  }',
  '}',
  '',
  'Integrated design brief markdown:',
  markdown
].join('\n');

const llmRequest = {
  model: input.model,
  messages: [
    {
      role: 'system',
      content: 'You are a senior promotional UI art director. Return valid JSON only. Use only the integrated design brief as the source of truth for the final image-generation prompt.'
    },
    { role: 'user', content: imagePromptInstruction }
  ],
  temperature: 0.2,
  response_format: { type: 'json_object' }
};

return [{
  json: {
    ...input,
    integratedDesignBriefMarkdown: markdown,
    integratedDesignBrief: brief,
    llmRequest
  }
}];

const input = $('Parse Validate Integrated Design Brief').item.json;
const response = $json;
const content = response.choices?.[0]?.message?.content || response.message?.content || response.content || response.text || response.output_text || '';
if (!content) throw new Error('LLM image prompt response is empty');

let generated;
try {
  const fence = String.fromCharCode(96, 96, 96);
  generated = typeof content === 'string'
    ? JSON.parse(content.replace(new RegExp('^' + fence + 'json\\s*', 'i'), '').replace(new RegExp(fence + '$', 'i'), '').trim())
    : content;
} catch (error) {
  throw new Error('Failed to parse image prompt JSON: ' + error.message);
}

if (!String(generated.imagePrompt || '').trim()) throw new Error('imagePrompt is required');
if (!generated.mdComplianceMap || typeof generated.mdComplianceMap !== 'object') throw new Error('mdComplianceMap is required');
if (!generated.layoutMapping || typeof generated.layoutMapping !== 'object') throw new Error('layoutMapping is required');

const requiredCompliance = [
  'layoutPhilosophy',
  'visualMood',
  'spacingRhythm',
  'composition',
  'componentStyle',
  'depthAndEffects',
  'shapeAndRadius',
  'promoPageImplications',
  'notColorFontOnlyProof'
];
const missingCompliance = requiredCompliance.filter((key) => !String(generated.mdComplianceMap[key] || '').trim());
if (missingCompliance.length) throw new Error('mdComplianceMap missing fields: ' + missingCompliance.join(', '));

let proof = String(generated.mdComplianceMap.notColorFontOnlyProof || '').trim();
if (proof.length < 40) {
  proof = [
    'The design is derived from the integrated design brief beyond color and font choices:',
    'it applies the selected MD layout philosophy, section order, spacing rhythm, component language, depth/effects, shape/radius rules, full-page vertical fit strategy, and Template 4 content mapping.'
  ].join(' ');
  generated.mdComplianceMap.notColorFontOnlyProof = proof;
}

const finalPrompt = [
  generated.imagePrompt,
  '',
  'Hard requirements:',
  '- Browserless desktop promotional web UI mockup: treat 1024x1536 as bitmap export size, not as a poster artboard or real page proportion.',
  '- Show the complete page from header to footer in one image; the bottom must not be cropped.',
  '- Include visible placements for promo title, lead text, CTA button, subline, title/description content, legal text, and footer, all in English.',
  '- No code, no browser chrome, no editor UI, no Figma canvas UI. Avoid print-design signals: no poster, flyer, brochure, presentation slide, magazine cover, single centered key visual, decorative poster typography, or paper margins.',
  '- Make the layout reflect the selected MD design concept, not only colors and fonts.',
  '- Preserve all 7 Template 4 sections in order: Header, Hero Banner, Step Bar, Content CTA, Image Text Row, Title and Description, Footer.',
  '- Follow the MD layout philosophy, spacing rhythm, composition, component style, depth/effects, shape/radius, dos, and donts.',
  '- If vertical space is tight, compress section heights and visuals instead of omitting or cropping content.',
  '- Render all visible UI text in English only; do not include Korean or any other non-English text.',
  generated.negativePrompt ? 'Avoid: ' + generated.negativePrompt : ''
].filter(Boolean).join('\n');

return [{
  json: {
    ...input,
    imagePrompt: finalPrompt,
    designBrief: generated.designBrief || input.designBrief,
    layoutMapping: generated.layoutMapping,
    mdComplianceMap: generated.mdComplianceMap
  }
}];

const input = $('Parse Validate Image Prompt').item.json;
const response = $json;
const currentItem = $input.item;

const cleanBase64 = (value) => String(value || '')
  .replace(/^data:image\/[a-zA-Z0-9.+-]+;base64,/, '')
  .replace(/\s/g, '');

const detectImage = (base64) => {
  const buf = Buffer.from(base64, 'base64');

  if (buf.length < 16) {
    throw new Error(`Invalid generated image data: decoded image is too small: ${buf.length} bytes`);
  }

  const isPng = buf[0] === 0x89 && buf[1] === 0x50 && buf[2] === 0x4e && buf[3] === 0x47;
  const isJpeg = buf[0] === 0xff && buf[1] === 0xd8 && buf[2] === 0xff;
  const isWebp = buf.slice(0, 4).toString('ascii') === 'RIFF' && buf.slice(8, 12).toString('ascii') === 'WEBP';

  if (isPng) return { mimeType: 'image/png', bytes: buf.length };
  if (isJpeg) return { mimeType: 'image/jpeg', bytes: buf.length };
  if (isWebp) return { mimeType: 'image/webp', bytes: buf.length };

  throw new Error(`Invalid generated image data: decoded data is not PNG/JPEG/WebP. bytes=${buf.length}`);
};

const findInlineImage = (value) => {
  if (!value || typeof value !== 'object') return null;

  const directInline = value.inlineData || value.inline_data;
  if (directInline?.data) return directInline;

  const parts = value.candidates?.[0]?.content?.parts || value.parts || value.content?.parts || [];
  const imagePart = parts.find((part) => part.inlineData?.data || part.inline_data?.data);
  if (imagePart) return imagePart.inlineData || imagePart.inline_data;

  return null;
};

const imageUrlFromApi =
  response.data?.[0]?.url ||
  response.output?.[0]?.url ||
  response.imageUrl ||
  response.image_url ||
  response.url ||
  '';

let b64 =
  response.data?.[0]?.b64_json ||
  response.output?.[0]?.b64_json ||
  response.image?.b64_json ||
  response.b64_json ||
  response.b64Json ||
  response.imageBase64 ||
  response.image_base64 ||
  '';

let mimeType = response.mimeType || response.mime_type || 'image/png';

if (!b64) {
  const inlineData = findInlineImage(response);
  if (inlineData?.data) {
    b64 = inlineData.data;
    mimeType = inlineData.mimeType || inlineData.mime_type || mimeType;
  }
}

if (!b64 && currentItem.binary) {
  const binaryEntry = Object.entries(currentItem.binary).find(([, item]) =>
    String(item.mimeType || '').startsWith('image/')
  );

  if (binaryEntry) {
    const [binaryPropertyName, binaryImage] = binaryEntry;
    const binaryBuffer = await this.helpers.getBinaryDataBuffer(0, binaryPropertyName);
    b64 = binaryBuffer.toString('base64');
    mimeType = binaryImage.mimeType || mimeType;
  }
}

let imageBytes = 0;

if (b64) {
  b64 = cleanBase64(b64);
  const detected = detectImage(b64);
  mimeType = detected.mimeType;
  imageBytes = detected.bytes;
}

if (!imageUrlFromApi && !b64) {
  throw new Error('Image generation response must include image url, inlineData, binary image, or base64 image data');
}

const imageDataUrl = b64 ? `data:${mimeType};base64,${b64}` : '';

const staticData = $getWorkflowStaticData('global');
staticData.designs = staticData.designs || {};
staticData.designs[input.id] = {
  imageUrlFromApi,
  hasEmbeddedImage: Boolean(imageDataUrl),
  imageMimeType: mimeType,
  imageBytes,
  imagePrompt: input.imagePrompt,
  designBrief: input.designBrief,
  layoutMapping: input.layoutMapping,
  mdComplianceMap: input.mdComplianceMap,
  integratedDesignBrief: input.integratedDesignBrief,
  integratedDesignBriefMarkdown: input.integratedDesignBriefMarkdown,
  promptMeta: input.promptMeta,
  payload: input,
  createdAt: new Date().toISOString()
};

const queryPath = 'promo-ui-design-view?id=' + encodeURIComponent(input.id);
const sourceUrl = String(input.n8nWebhookUrl || '').trim();

const buildDesignUrl = (url) => {
  if (!url) return '';

  const replaced = url.replace(/promo-ui-design-generate\/?(?:\?.*)?$/, queryPath);
  if (replaced !== url) return replaced;

  try {
    const parsed = new URL(url);
    parsed.pathname = parsed.pathname
      .replace(/\/$/, '')
      .replace(/promo-ui-design-generate$/, 'promo-ui-design-view');
    parsed.search = '?id=' + encodeURIComponent(input.id);
    return parsed.toString();
  } catch (error) {
    return url.replace(/\/promo-ui-design-generate\/?(?:\?.*)?$/, '/' + queryPath);
  }
};

let designUrl = buildDesignUrl(sourceUrl);

if (!designUrl || /promo-ui-design-generate\/?(?:\?.*)?$/.test(designUrl)) {
  const headers = $('Generate Promo UI Design').item.json.headers || {};
  const proto = headers['x-forwarded-proto'] || 'https';
  const host = headers['x-forwarded-host'] || headers.host || '';
  designUrl = host ? proto + '://' + host + '/webhook/' + queryPath : '/webhook/' + queryPath;
}

const resultType = imageUrlFromApi || imageDataUrl ? 'image' : 'view';

return [
  {
    json: {
      ok: true,
      id: input.id,
      resultType,
      designUrl,
      imageUrl: imageUrlFromApi || imageDataUrl || '',
      hasEmbeddedImage: Boolean(imageDataUrl),
      imageMimeType: mimeType,
      imageBytes,
      designBrief: input.designBrief,
      layoutMapping: input.layoutMapping,
      mdComplianceMap: input.mdComplianceMap,
      integratedDesignBrief: input.integratedDesignBrief,
      integratedDesignBriefMarkdown: input.integratedDesignBriefMarkdown,
      promptMeta: input.promptMeta,
      imagePrompt: input.imagePrompt,
      payload: input
    }
  }
];

const id = $json.params?.id || $json.query?.id || '';
const staticData = $getWorkflowStaticData('global');
const design = staticData.designs?.[id];
const src = design?.imageUrlFromApi || '';
const title = design?.payload?.promo?.title || 'Promo UI Design';
const stampDate = new Date(design?.createdAt || Date.now());
const padStamp = (value) => String(value).padStart(2, '0');
const stamp = String(stampDate.getFullYear()).slice(-2) + padStamp(stampDate.getMonth() + 1) + padStamp(stampDate.getDate()) + padStamp(stampDate.getHours()) + padStamp(stampDate.getMinutes());
const html = src
  ? `<!doctype html><html lang='ko'><head><meta charset='utf-8'><meta name='viewport' content='width=device-width,initial-scale=1'><title>${title}</title><style>body{margin:0;background:#f6f8fc;font-family:Arial,sans-serif;color:#111827}.wrap{max-width:1540px;margin:0 auto;padding:24px}.bar{display:flex;justify-content:space-between;gap:16px;align-items:center;margin-bottom:16px}.title-row{display:flex;align-items:center;gap:8px}.stamp{display:inline-flex;align-items:center;min-height:20px;padding:2px 7px;border:1px solid #dbe3ef;border-radius:999px;background:#fff;color:#64748b;font-size:11px;font-weight:700}.meta{color:#64748b;font-size:13px}img{display:block;width:100%;height:auto;background:#fff}</style></head><body><main class='wrap'><div class='bar'><div class='title-row'><strong>${title}</strong><span class='stamp'>${stamp}</span></div><span class='meta'>${id}</span></div><img src='${src}' alt='Generated promo UI design'></main></body></html>`
  : `<!doctype html><html lang='ko'><head><meta charset='utf-8'><title>UI design not found</title></head><body style='font-family:Arial,sans-serif;padding:40px'><h1>UI design not found</h1><p>No generated UI design was stored for id: ${id}</p></body></html>`;
return [{ json: { html } }];

const response = $json;
const content =
  response.choices?.[0]?.message?.content ||
  response.message?.content ||
  response.content ||
  response.text ||
  '';

return [
  {
    json: {
      contentLength: String(content).length,
      contentPreviewStart: String(content).slice(0, 1000),
      contentPreviewEnd: String(content).slice(-1000)
    }
  }
];
